# Dynamic metadata filter extraction from natural language
# Instead of requiring the user to write structured filter queries, extract
# filter intent from their natural language question using an LLM or regex.

from langchain_openai import ChatOpenAI
from langchain_core.prompts import ChatPromptTemplate
from langchain_core.output_parsers import JsonOutputParser
from langchain_community.vectorstores import Chroma
from langchain_openai import OpenAIEmbeddings

embeddings = OpenAIEmbeddings(model="text-embedding-3-small")
vectorstore = Chroma(persist_directory="./chroma_db", embedding_function=embeddings)
llm = ChatOpenAI(model="gpt-4o-mini", temperature=0)

FILTER_SCHEMA = {
    "type": "object",
    "properties": {
        "department": {"type": "string", "enum": ["HR", "Legal", "Finance", "Engineering", "all"]},
        "year_min": {"type": "integer"},
        "year_max": {"type": "integer"},
        "doc_type": {"type": "string", "enum": ["policy", "contract", "faq", "general"]},
    },
}


def extract_filter_from_query(question: str) -> dict:
    """
    Use an LLM to extract structured filter intent from a natural language query.
    Returns a Chroma-compatible filter dict.
    """
    prompt = ChatPromptTemplate.from_template(
        "Extract filter intent from this question. Return a JSON object with only "
        "the fields that are explicitly constrained in the question. "
        "Valid fields: department (HR/Legal/Finance/Engineering), "
        "year_min (int), year_max (int), doc_type (policy/contract/faq). "
        "Return {{}} if no constraints are mentioned.\n\nQuestion: {question}"
    )
    try:
        raw = (prompt | llm | JsonOutputParser()).invoke({"question": question})
    except Exception:
        return {}

    # Convert to Chroma filter operators
    chroma_filter = {}
    clauses = []
    if "department" in raw and raw["department"] != "all":
        clauses.append({"department": {"$eq": raw["department"]}})
    if "doc_type" in raw:
        clauses.append({"doc_type": {"$eq": raw["doc_type"]}})
    if "year_min" in raw and "year_max" in raw:
        clauses.append({"year": {"$gte": raw["year_min"]}})
        clauses.append({"year": {"$lte": raw["year_max"]}})
    elif "year_min" in raw:
        clauses.append({"year": {"$gte": raw["year_min"]}})

    if len(clauses) == 1:
        return clauses[0]
    elif len(clauses) > 1:
        return {"$and": clauses}
    return {}


def smart_filtered_search(question: str, k: int = 4):
    filters = extract_filter_from_query(question)
    print(f"Extracted filter: {filters}")
    return vectorstore.similarity_search(question, k=k, filter=filters if filters else None)


# Examples
r1 = smart_filtered_search("HR policies updated after 2023")
# → filter: {$and: [{department: {$eq: HR}}, {year: {$gte: 2023}}]}

r2 = smart_filtered_search("show me all Legal contracts")
# → filter: {$and: [{department: {$eq: Legal}}, {doc_type: {$eq: contract}}]}

r3 = smart_filtered_search("what is the cancellation policy?")
# → filter: {} (no structural constraints — pure semantic search)
